INSERT INTO fortune_contents (result_key, category, title, content_md, type_slug) VALUES
('1_water', 'nine_star', '一白水星', '知恵と柔軟性を持ち、困難な状況でも流れるように対処する能力があります。水のように形を変えながら進む性質を持ち、洞察力に優れています。コミュニケーション能力が高く、人との調和を大切にする傾向があります。', 'nine_star'),
('2_earth', 'nine_star', '二黒土星', '誠実で堅実な性格。大地のように安定感があり、周囲から信頼される存在です。コツコツと努力を重ねることで大きな成果を得る傾向があります。母性的な優しさを持ち、人を育てる才能があります。', 'nine_star'),
('3_wood', 'nine_star', '三碧木星', '若々しく活発なエネルギーを持ち、新しいことに挑戦する意欲に満ちています。雷のような瞬発力があり、行動力に優れています。発想が豊かで、言葉や音楽など表現活動に才能を発揮しやすい傾向があります。', 'nine_star'),
('4_wood', 'nine_star', '四緑木星', '穏やかで調和を重んじる性格。風のように人との縁をつなぐ能力があり、社交性に優れています。柔軟性と協調性を持ち、周囲との関係を円滑に保つことができます。商業や対人関係の仕事に向いています。', 'nine_star'),
('5_earth', 'nine_star', '五黄土星', '強いリーダーシップと統率力を持つ星。中心的な存在として周囲を引っ張る力があります。意志が強く、困難に立ち向かう勇気があります。ただし、エネルギーが強すぎるため、バランスを保つことが重要です。', 'nine_star'),
('6_metal', 'nine_star', '六白金星', '高潔で誇り高い性格。天の気質を持ち、理想を追求する傾向があります。正義感が強く、リーダーシップを発揮します。品格と威厳を備え、目上の人から信頼されやすい星です。', 'nine_star'),
('7_red', 'nine_star', '七赤金星', '社交的で明るく、人を楽しませる才能があります。金運に恵まれやすく、特に対人関係を通じて富を得る傾向があります。話術に優れ、営業や接客業に向いています。喜びを分かち合うことを大切にします。', 'nine_star'),
('8_earth', 'nine_star', '八白土星', '山のようにどっしりとした安定感と忍耐力を持ちます。変革と継承の両方の性質を持ち、古いものを大切にしながら新しいものを生み出す力があります。不動産や相続に縁がある傾向があります。', 'nine_star'),
('9_fire', 'nine_star', '九紫火星', '華やかで知性と美的センスに優れています。火のように情熱的で、人を惹きつける魅力があります。直感力が鋭く、芸術や学問の分野で才能を発揮しやすい星です。名誉や地位を得やすい傾向があります。', 'nine_star')
INSERT INTO fortune_contents (result_key, category, title, content_md, type_slug) VALUES
('lp_0', 'numerology', 'ライフパスナンバー0', '無限の可能性と新たな始まりを象徴します。まだ形になっていない純粋なエネルギーを持ち、どんな方向にも進める柔軟性があります。精神的な成長と宇宙とのつながりを重視する特別な数です。', 'numerology'),
('lp_1', 'numerology', 'ライフパスナンバー1', 'リーダーシップと独立心に満ちた人生を歩みます。新しい道を切り開く開拓者の資質を持ち、自分の信念に従って行動する勇気があります。独創性と決断力を活かし、人生の先頭に立つ運命です。', 'numerology'),
('lp_2', 'numerology', 'ライフパスナンバー2', '調和と協力を重視する人生。優れた調整能力と共感力を持ち、人と人をつなぐ役割を果たします。感受性が豊かで、芸術的センスがあります。パートナーシップを通じて成長する運命です。', 'numerology'),
('lp_3', 'numerology', 'ライフパスナンバー3', '創造性豊かで表現力に優れています。芸術やコミュニケーションの分野で才能を発揮しやすく、周囲を明るくする存在です。楽観的で社交的な性格を持ち、人生を楽しむ才能があります。', 'numerology'),
('lp_4', 'numerology', 'ライフパスナンバー4', '堅実で実直な人生を歩みます。組織力と計画性に優れ、着実に基盤を築く能力があります。責任感が強く、誠実な性格で信頼されます。忍耐強く努力を重ねることで大きな成果を得る運命です。', 'numerology'),
('lp_5', 'numerology', 'ライフパスナンバー5', '自由と変化を愛する冒険的な人生。好奇心旺盛で、多様な経験を通じて成長します。適応力が高く、新しい環境にもすぐに馴染めます。コミュニケーション能力に優れ、情報を伝える役割を果たします。', 'numerology'),
('lp_6', 'numerology', 'ライフパスナンバー6', '愛と奉仕の精神を持つ人生。家族や共同体に対する責任感が強く、調和のとれた環境を作る才能があります。美的センスに優れ、芸術や癒しの分野で活躍しやすい運命です。', 'numerology'),
('lp_7', 'numerology', 'ライフパスナンバー7', '精神性と知性を追求する人生。内省的で深い思考力を持ち、真理を探求します。直感力と分析力の両方に優れ、研究や学問の分野で才能を発揮します。孤独を恐れず、自己の成長を重視する運命です。', 'numerology'),
('lp_8', 'numerology', 'ライフパスナンバー8', '力と成功を象徴する人生。ビジネスセンスと実行力に優れ、物質的な豊かさを実現する能力があります。野心的で目標達成への意欲が強く、リーダーシップを発揮します。バランスを保つことで真の成功を得る運命です。', 'numerology'),
('lp_9', 'numerology', 'ライフパスナンバー9', '普遍的な愛と人道主義の人生。慈悲深く、人類全体の幸福を願う広い視野を持ちます。芸術的才能と霊性が高く、多くの人々に影響を与える運命です。完成と新たな始まりの両方の意味を持つ数です。', 'numerology'),
('lp_11', 'numerology', 'マスターナンバー11', '霊的な直感と洞察力を持つ特別な人生。高い理想と使命感を持ち、人々を導く役割を果たします。感受性が非常に強く、精神世界と物質世界をつなぐ架け橋となる運命です。', 'numerology'),
('lp_22', 'numerology', 'マスターナンバー22', '壮大なビジョンを現実化する力を持つ人生。マスタービルダーと呼ばれ、大きな夢を具体的な形にする能力があります。実践力と理想主義を兼ね備え、世界に永続的な影響を与える運命です。', 'numerology'),
('lp_33', 'numerology', 'マスターナンバー33', '無条件の愛と奉仕を体現する最高位の人生。マスターティーチャーと呼ばれ、深い共感力と癒しの力を持ちます。自己犠牲的な愛で人々を導き、精神的な目覚めをもたらす使命を持つ運命です。', 'numerology')
INSERT INTO fortune_contents (result_key, category, title, content_md, type_slug) VALUES
('stem_1', 'four_pillars', '甲（きのえ）木', '大木のように真っすぐで堂々とした性格。正義感が強く、曲がったことを嫌います。成長志向が強く、常に上を目指す向上心があります。リーダーシップを発揮し、周囲を引っ張る力を持っています。', 'four_pillars'),
('stem_2', 'four_pillars', '乙（きのと）木', '草花のように柔軟で繊細な性格。適応力が高く、環境に応じて形を変えることができます。美的センスに優れ、芸術的な才能があります。人当たりが柔らかく、協調性を持って人間関係を築きます。', 'four_pillars'),
('stem_3', 'four_pillars', '丙（ひのえ）火', '太陽のように明るく情熱的な性格。エネルギッシュで前向きな姿勢を持ち、周囲を照らす存在です。社交性に優れ、人を惹きつける魅力があります。正々堂々とした態度で物事に取り組みます。', 'four_pillars'),
('stem_4', 'four_pillars', '丁（ひのと）火', '灯火のように優しく暖かな性格。細やかな気配りができ、人を癒す力があります。感受性が豊かで、芸術や精神的な分野に才能を発揮します。控えめながらも確かな存在感を持っています。', 'four_pillars'),
('stem_5', 'four_pillars', '戊（つちのえ）土', '山のようにどっしりとした安定感のある性格。責任感が強く、頼りがいのある存在です。包容力があり、周囲を支える土台となります。実直で誠実な態度で信頼を得ます。', 'four_pillars'),
('stem_6', 'four_pillars', '己（つちのと）土', '田畑の土のように育成と養育の力を持つ性格。面倒見が良く、人を育てる才能があります。現実的で実用的な思考を持ち、着実に物事を進めます。柔軟性と粘り強さを兼ね備えています。', 'four_pillars'),
('stem_7', 'four_pillars', '庚（かのえ）金', '刀剣のように鋭く強い意志を持つ性格。正義感が強く、白黒をはっきりさせます。行動力と決断力に優れ、困難な状況でも立ち向かう勇気があります。潔癖で完璧主義的な一面があります。', 'four_pillars'),
('stem_8', 'four_pillars', '辛（かのと）金', '宝石のように繊細で美しい感性を持つ性格。品位と気品があり、洗練されたセンスを持っています。完璧を追求する傾向があり、細部にまでこだわります。知的で冷静な判断力があります。', 'four_pillars'),
('stem_9', 'four_pillars', '壬（みずのえ）水', '大海のように広大で深い包容力を持つ性格。知恵と柔軟性に優れ、状況に応じて対応できます。社交性が高く、多くの人との交流を持ちます。変化を恐れず、流れに乗る能力があります。', 'four_pillars'),
('stem_10', 'four_pillars', '癸（みずのと）水', '雨や露のように静かで優しい性格。内面的な深さと感受性を持ち、精神的な世界を大切にします。控えめながらも浸透力があり、じわじわと影響を与えます。直感力と想像力に優れています。', 'four_pillars')
